import { createFeatureSelector, createSelector } from '@ngrx/store';
import { feedsFeatureKey } from './feeds.reducer';
export const getFeedsState = createFeatureSelector(feedsFeatureKey);
export const getFeedsIsLoaded = createSelector(getFeedsState, state => state.isLoaded);
export const getFeedsError = createSelector(getFeedsState, state => state.error);
export const getAllFeeds = createSelector(getFeedsState, state => state.feeds);
